import{_ as e,o as r,c as t,a2 as i}from"./chunks/framework.BK37cAdB.js";const _=JSON.parse('{"title":"사용자 관리","description":"","frontmatter":{},"headers":[],"relativePath":"work-setting/user.md","filePath":"work-setting/user.md","lastUpdated":1781518877000}'),o={name:"work-setting/user.md"};function s(l,a,n,h,d,u){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="사용자-관리" tabindex="-1">사용자 관리 <a class="header-anchor" href="#사용자-관리" aria-label="Permalink to &quot;사용자 관리&quot;">​</a></h1><p>시스템에 접속하는 구성원 계정을 생성하고, 각 사용자의 활동 현황을 통합적으로 관리하는 <strong>사용자</strong> 페이지에 대한 가이드입니다.</p><h2 id="_1-화면-개요" tabindex="-1">1. 화면 개요 <a class="header-anchor" href="#_1-화면-개요" aria-label="Permalink to &quot;1. 화면 개요&quot;">​</a></h2><p>사용자 관리 화면은 전사적인 사용자 목록을 제공하며, 특정 사용자가 어떤 프로젝트에 참여하고 있는지, 할당된 업무의 처리 현황은 어떠한지 등 상세한 프로필 정보를 확인하고 관리할 수 있는 기능을 제공합니다.</p><h2 id="_2-주요-기능-안내" tabindex="-1">2. 주요 기능 안내 <a class="header-anchor" href="#_2-주요-기능-안내" aria-label="Permalink to &quot;2. 주요 기능 안내&quot;">​</a></h2><h3 id="👥-사용자-목록-및-검색" tabindex="-1">👥 사용자 목록 및 검색 <a class="header-anchor" href="#👥-사용자-목록-및-검색" aria-label="Permalink to &quot;👥 사용자 목록 및 검색&quot;">​</a></h3><ul><li><strong>전체 목록 조회</strong>: 시스템에 등록된 모든 사용자의 이름, 아이디, 이메일, 가입일 등을 한눈에 확인합니다.</li><li><strong>사용자 식별</strong>: 목록에서 특정 사용자를 클릭하여 해당 사용자의 상세 활동 대시보드로 이동할 수 있습니다.</li></ul><h3 id="🔍-사용자-상세-프로필-user-view" tabindex="-1">🔍 사용자 상세 프로필 (User View) <a class="header-anchor" href="#🔍-사용자-상세-프로필-user-view" aria-label="Permalink to &quot;🔍 사용자 상세 프로필 (User View)&quot;">​</a></h3><p>특정 사용자를 선택하면 해당 인원과 관련된 모든 업무 데이터를 집계하여 보여줍니다.</p><ul><li><strong>참여 프로젝트</strong>: 해당 사용자가 구성원으로 포함되어 있는 모든 프로젝트 리스트를 확인합니다.</li><li><strong>업무 통계</strong>: 사용자에게 할당된 업무의 총 개수와 완료/진행 중인 업무의 비중을 시각적으로 파악합니다.</li><li><strong>최근 활동 기록</strong>: 해당 사용자가 최근에 생성하거나 수정한 업무, 게시글 등 최신 활동 로그(최대 10건)를 추적합니다.</li></ul><h3 id="📝-계정-생성-및-정보-수정" tabindex="-1">📝 계정 생성 및 정보 수정 <a class="header-anchor" href="#📝-계정-생성-및-정보-수정" aria-label="Permalink to &quot;📝 계정 생성 및 정보 수정&quot;">​</a></h3><ul><li><strong>사용자 생성</strong> (<i class="mdi mdi-plus-circle text-success"></i>): 새로운 구성원의 계정을 생성하고 기본 인적 사항을 등록합니다.</li><li><strong>정보 업데이트</strong>: 사용자의 이메일, 연락처, 권한 상태 등 프로필 정보를 최신으로 유지합니다.</li></ul><h2 id="_3-관리자-이용-팁" tabindex="-1">3. 관리자 이용 팁 <a class="header-anchor" href="#_3-관리자-이용-팁" aria-label="Permalink to &quot;3. 관리자 이용 팁&quot;">​</a></h2><ul><li><strong>업무 부하 파악</strong>: 사용자 상세 보기의 업무 통계를 통해 특정 팀원에게 업무가 과도하게 집중되어 있지는 않은지 확인하여 업무를 재배분할 수 있습니다.</li><li><strong>활동 추적</strong>: 활동 로그를 활용하면 특정 이슈의 변경 이력이나 사용자의 최근 작업 흐름을 파악하는 데 도움이 됩니다.</li><li><strong>권한 관리</strong>: 사용자가 퇴사하거나 부서가 변경된 경우, 사용자 수정 기능을 통해 계정의 활성화 상태나 접근 권한을 즉시 조정하십시오.</li></ul>',14)])])}const g=e(o,[["render",s]]);export{_ as __pageData,g as default};
